def _extract_cv_from_staged_stats(staged_stats, staged_comparison_df=None, staged_company_id=None):
    if isinstance(staged_stats, dict):
        for key in ("cv", "coefficient_of_variation", "exhaust_gas_cv", "population_cv"):
            if key in staged_stats and staged_stats[key] is not None:
                return float(staged_stats[key])
    if staged_comparison_df is not None and staged_company_id is not None:
        df = staged_comparison_df
        id_cols = [c for c in df.columns if c.lower() in ("company_id", "id")]
        cv_cols = [c for c in df.columns if "cv" in c.lower() or "coefficient" in c.lower()]
        if id_cols and cv_cols:
            matched = df[df[id_cols[0]] == staged_company_id]
            if len(matched) > 0:
                return float(matched.iloc[0][cv_cols[0]])
    raise ValueError("未能从已暂存的中间变量中提取CV值。")

